    ('anderson-ferreira', 'PL', '179', 2011, 'Concede dedução do Imposto de Renda às Empresas que contratarem trabalhadores com menos de vinte e um ou mais de quarenta e cinco anos de idade.', 'Camara', '491235', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=837714', 'anderson-ferreira-camara-completo-autoria-principal-tipos-verificados-2011-2016-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2011_2016_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"anderson-ferreira-camara-completo-20260511","coverage_id":"anderson-ferreira-camara-completo-autoria-principal-tipos-verificados-2011-2016-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2011_2016_cutoff_20260511","previous_coverage_id":"anderson-ferreira-camara-autoria-principal-ampliado-parcial-lote-a-20260505","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260505","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":160551,"proposicao_id_api":"491235","data_apresentacao":"2011-02-08T15:21","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Anderson Ferreira","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/160551","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/491235","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/491235/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/491235","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"autoria_principal_verificada":true}'::jsonb)
) AS v(
  slug,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
);

DO $$
DECLARE
  cand_id uuid;
  seed_count int;
  target_count int;
  metadata_count int;
  lme_count int;
  other_slug_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'anderson-ferreira';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'anderson-ferreira: candidato ausente neste banco local/CI minimo; seed completo escopado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO seed_count FROM _anderson_camara_completo_seed;

  IF seed_count <> 40 THEN
    RAISE EXCEPTION 'Pre-condicao anderson-ferreira: seed tem % rows, esperado 40', seed_count;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao anderson-ferreira: LME mudou de 0 para %', lme_count;
  END IF;

  INSERT INTO projetos_lei (
    candidato_id,
    tipo,
    numero,
    ano,
    ementa,
    fonte,
    proposicao_id_api,
    url_inteiro_teor,
    coverage_id,
    coverage_scope,
    metadata
  )
  SELECT
    cand_id,
    seed.tipo,
    seed.numero,
    seed.ano,
    seed.ementa,
    seed.fonte,
    seed.proposicao_id_api,
    seed.url_inteiro_teor,
    seed.coverage_id,
    seed.coverage_scope,
    seed.metadata
  FROM _anderson_camara_completo_seed seed
  ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
    tipo = EXCLUDED.tipo,
    numero = EXCLUDED.numero,
    ano = EXCLUDED.ano,
    ementa = EXCLUDED.ementa,
    fonte = EXCLUDED.fonte,
    url_inteiro_teor = EXCLUDED.url_inteiro_teor,
    coverage_id = EXCLUDED.coverage_id,
    coverage_scope = EXCLUDED.coverage_scope,
    metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
  WHERE projetos_lei.coverage_id IS NULL
     OR projetos_lei.coverage_id = EXCLUDED.coverage_id
     OR projetos_lei.coverage_id = 'anderson-ferreira-camara-autoria-principal-ampliado-parcial-lote-a-20260505'
     OR projetos_lei.coverage_id LIKE 'anderson-ferreira-camara-autoria-principal-ampliado-parcial%';

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'anderson-ferreira-camara-completo-autoria-principal-tipos-verificados-2011-2016-cutoff-20260511'
    AND coverage_scope = 'inventario_completo_camara_autoria_principal_tipos_verificados_2011_2016_cutoff_20260511';

  SELECT count(*) INTO metadata_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'anderson-ferreira-camara-completo-autoria-principal-tipos-verificados-2011-2016-cutoff-20260511'
    AND coverage_scope = 'inventario_completo_camara_autoria_principal_tipos_verificados_2011_2016_cutoff_20260511'
    AND metadata->>'coverage_status' = 'completo_escopado'
    AND metadata->>'tabela_alvo' = 'projetos_lei'
    AND metadata->>'legislacao_mandato_executivo_mixed' = 'false'
    AND metadata->>'autoria_principal_verificada' = 'true';

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;

  SELECT count(*) INTO other_slug_count
  FROM projetos_lei
  WHERE candidato_id <> cand_id
    AND coverage_id = 'anderson-ferreira-camara-completo-autoria-principal-tipos-verificados-2011-2016-cutoff-20260511';

  IF target_count <> 40 THEN
    RAISE EXCEPTION 'Pos-condicao anderson-ferreira: % rows completas, esperado 40', target_count;
  END IF;

  IF metadata_count <> 40 THEN
    RAISE EXCEPTION 'Pos-condicao anderson-ferreira: % rows com metadata completa, esperado 40', metadata_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-condicao anderson-ferreira: LME mudou de 0 para %', lme_count;
  END IF;

  IF other_slug_count <> 0 THEN
    RAISE EXCEPTION 'Pos-condicao anderson-ferreira: % rows de outros slugs com coverage_id alvo', other_slug_count;
  END IF;
END $$;
